"""
Utility snippet to rename downloaded files if needed:

import os
folder = str(NDVI_DIR) + '/'
for i in tochange:
    try:
        file_name = i.split('/')[-1]
        file_name = file_name[4:]
        os.rename(i, folder + file_name)
        print(file_name)
    except:
        pass
"""

import os
import requests
from pathlib import Path
import sys
sys.path.insert(0, str(Path(__file__).resolve().parents[1]))
from config import NDVI_DIR, CORE

folder = str(NDVI_DIR / 'January') + '/'

# Set NASA_EARTHDATA_TOKEN env var — see land_use_fetch.py for instructions
token = os.environ.get('NASA_EARTHDATA_TOKEN')
if not token:
    raise EnvironmentError("NASA_EARTHDATA_TOKEN environment variable not set.")

counter = 0
for url in nvdi01:

    file_name = url.split('/')[-1]
    data_path = Path(folder + file_name)
    counter = counter + 1
    if os.path.isfile(data_path):
        print(f'In folder {file_name}...', counter, "/", str(len(nvdi01)))
    else:
        header = {"Authorization": f"Bearer {token}"}
        response = requests.get(url, headers=header)
        content = response.content
        data_path.write_bytes(content)
        print(f'Downloading {file_name}...', counter, "/", str(len(nvdi01)))
    

"""
Dealing with CO2 data 
"""
import pandas as pd 
import os

folder_path = str(CORE / "CO2")

# Initialize an empty DataFrame to store the merged data
merged_data = pd.DataFrame()

# Loop through all files in the directory
for filename in os.listdir(folder_path):
    if filename.endswith('.csv') and filename.startswith('CO2_'):
        # Read each CSV file into a DataFrame
        df = pd.read_csv(os.path.join(folder_path, filename))
        
        # Extract year and month from the filename
        year = int(filename.split('_')[1])
        month = str(filename.split('_')[2])
        
        # Create a new column with the year and month information
        df['year'] = year
        df.rename(columns = {df.columns[10]: 'CO2sum', df.columns[11]:'CO2mean', df.columns[12]:'CO2median', }, inplace = True)        

        # Append the DataFrame to the merged_data DataFrame
        merged_data = merged_data.append(df, ignore_index=True)




agg_func = {'CVE_ENT': 'max', 'CVE_MUN': 'max', 'NOMGEO': 'first', 'CO2sum': 'mean', 'CO2mean': 'mean',
               'CO2median': 'mean'}
merged_data = merged_data.groupby(['CVEGEO', 'year']).agg(agg_func)
merged_data.to_csv(str(CORE / "CO2data.csv"), index = True)


######## FOR THE RINGS ######
# Loop through all files in the directory

for filename in os.listdir(folder_path):
    if filename.endswith('.csv') and filename.startswith('ring_'):
        # Read each CSV file into a DataFrame
        df = pd.read_csv(os.path.join(folder_path, filename))
        
        # Extract year and month from the filename
        year = int(filename.split('_')[1])
        month = str(filename.split('_')[2])
        
        # Create a new column with the year and month information
        df['year'] = year
        df=df[df.columns[[0, 112, 113, 114 ,115, 116 ,117, 118]]]
        df.rename(columns = {df.columns[4]: 'CO2sum', df.columns[5]:'CO2mean', df.columns[6]:'CO2median', }, inplace = True)        

        # Append the DataFrame to the merged_data DataFrame
        merged_data = merged_data.append(df, ignore_index=True)




agg_func = { 'distance': 'mean' , 'CO2sum': 'mean', 'CO2mean': 'mean', 'CO2median': 'mean'}
merged_data = merged_data.groupby(['ID No', 'year', 'ringId']).agg(agg_func)
merged_data.to_csv(str(CORE / "CO2ring_data.csv"), index = True)

